function Dashboard() {
  const role = localStorage.getItem("role");

  return (
    <div>
      <h2>{role?.toUpperCase()} Dashboard</h2>

      {role === "student" && <p>📚 View & Request Books</p>}

      {role === "librarian" && (
        <>
          <p>📦 Manage Inventory</p>
          <p>📖 Issue / Return Books</p>
        </>
      )}

      {role === "admin" && (
        <>
          <p>👥 Manage Users</p>
          <p>📊 View Reports</p>
        </>
      )}
      {role === "librarian" && (
  <>
    <p>📦 <a href="/inventory">Manage Inventory</a></p>
    <p>📖 Issue / Return Books</p>
    <p>💰 <a href="/fine">Fine Calculator</a></p>

  </>
  
)}
{role === "admin" && (
  <>
    <p>👥 Manage Users</p>
    <p>📊 <a href="/reports">View Reports</a></p>
  </>
)}

    </div>
  );
}

export default Dashboard;
